import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

const API = 'http://localhost:5000';

function App() {
  const [grid, setGrid] = useState([]);
  const [circuits, setCircuits] = useState([]);
  const [selectedCircuit, setSelectedCircuit] = useState('');
  const [gridPositions, setGridPositions] = useState({});
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Load driver grid and circuits on mount
  useEffect(() => {
    const loadData = async () => {
      try {
        const [gridRes, circuitRes] = await Promise.all([
          axios.get(`${API}/api/grid-info`),
          axios.get(`${API}/api/circuits`)
        ]);
        
        setDrivers(driversRes.data);
        setConstructors(constructorsRes.data);
        setCircuits(circuitsRes.data);
        
        // Set defaults
        if (driversRes.data.length > 0) setSelectedDriver(driversRes.data[0].id);
        if (constructorsRes.data.length > 0) setSelectedConstructor(constructorsRes.data[0].id);
        if (circuitsRes.data.length > 0) setSelectedCircuit(circuitsRes.data[0].id);
      } catch (err) {
        setError('Failed to load dropdown data');
        console.error(err);
      }
    };

    fetchData();
  }, []);

  // Handle prediction request
  const handlePredict = async () => {
    if (!selectedDriver || !selectedConstructor || !selectedCircuit) {
      setError('Please select all options');
      return;
    }

    setLoading(true);
    setError(null);
    setPrediction(null);

    try {
      const response = await axios.post(`${API_BASE}/api/predict`, {
        driver_id: parseInt(selectedDriver),
        constructor_id: parseInt(selectedConstructor),
        circuit_id: parseInt(selectedCircuit),
        grid_position: gridPosition
      });

      setPrediction(response.data);
    } catch (err) {
      setError(err.response?.data?.error || 'Prediction failed');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app">
      <header className="app-header">
        <h1>🏎️ F1 Podium Predictor</h1>
        <p>Predict your driver's podium chances</p>
      </header>

      <div className="container">
        <div className="input-panel">
          <h2>Configure Race</h2>

          {/* Driver Dropdown */}
          <div className="form-group">
            <label htmlFor="driver">Driver</label>
            <select
              id="driver"
              value={selectedDriver}
              onChange={(e) => setSelectedDriver(e.target.value)}
            >
              <option value="">-- Select Driver --</option>
              {drivers.map(d => (
                <option key={d.id} value={d.id}>{d.name}</option>
              ))}
            </select>
          </div>

          {/* Constructor Dropdown */}
          <div className="form-group">
            <label htmlFor="constructor">Constructor</label>
            <select
              id="constructor"
              value={selectedConstructor}
              onChange={(e) => setSelectedConstructor(e.target.value)}
            >
              <option value="">-- Select Constructor --</option>
              {constructors.map(c => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>

          {/* Circuit Dropdown */}
          <div className="form-group">
            <label htmlFor="circuit">Circuit</label>
            <select
              id="circuit"
              value={selectedCircuit}
              onChange={(e) => setSelectedCircuit(e.target.value)}
            >
              <option value="">-- Select Circuit --</option>
              {circuits.map(circ => (
                <option key={circ.id} value={circ.id}>{circ.name}</option>
              ))}
            </select>
          </div>

          {/* Grid Position Slider */}
          <div className="form-group">
            <label htmlFor="grid">Grid Position: {gridPosition}</label>
            <input
              id="grid"
              type="range"
              min="1"
              max="20"
              value={gridPosition}
              onChange={(e) => setGridPosition(parseInt(e.target.value))}
              className="slider"
            />
          </div>

          {/* Error Display */}
          {error && <div className="error-box">{error}</div>}

          {/* Predict Button */}
          <button
            onClick={handlePredict}
            disabled={loading}
            className="predict-btn"
          >
            {loading ? 'Predicting...' : 'PREDICT PODIUM'}
          </button>
        </div>

        {/* Prediction Result Panel */}
        {prediction && (
          <div className="result-panel">
            <h2>Prediction Result</h2>
            
            <div className="result-header">
              <p>Driver {prediction.driver_id} @ Constructor {prediction.constructor_id}</p>
              <p>Grid: P{prediction.grid_position} → Circuit {prediction.circuit_id}</p>
            </div>

            <div className="probability-display">
              <div className="main-prediction">
                <span className="label">Overall Prediction</span>
                <div className="percentage">{prediction.ensemble_podium_chance}</div>
                <div className={`verdict ${prediction.prediction === 'PODIUM' ? 'podium' : 'no-podium'}`}>
                  {prediction.prediction}
                </div>
              </div>

              <div className="model-breakdown">
                <div className="model-result">
                  <h4>Random Forest</h4>
                  <p className="model-prob">{prediction.random_forest_podium_chance}</p>
                </div>
                <div className="model-result">
                  <h4>CatBoost</h4>
                  <p className="model-prob">{prediction.catboost_podium_chance}</p>
                </div>
                <div className="model-result">
                  <h4>Ensemble (Avg)</h4>
                  <p className="model-prob">{prediction.ensemble_podium_chance}</p>
                </div>
              </div>
            </div>

            <button onClick={() => handlePredict()} className="retry-btn">
              Try Another Prediction
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
